#!/usr/bin/env bash
# Pack and sideload the Microsoft Teams app for {{.AgentName}} -- one command.
#
# Generated by 'azd deploy' (activity protocol). Every id below was filled in by
# azd from the deployed agent and its auto-created Azure Bot, so this script does
# NOT call Azure -- it just packages and installs the Teams app.
#
# What it does (idempotent -- safe to re-run):
#   1. builds a Teams app package (manifest.json + icons) in a temp dir,
#   2. ensures the Microsoft 365 Agents Toolkit CLI (atk) is installed,
#   3. installs the app FOR THE CURRENT USER (atk install --scope Personal --
#      no org-catalog admin approval needed; your tenant must still allow custom
#      app upload/sideloading, which a Teams admin can enable if it is off), and
#   4. prints an "Open in Teams" chat deep link.
#
# Prerequisites: Node.js (npm) for the atk CLI, and a one-time 'atk auth login m365'
# with your M365 account (this script launches it for you if you are not signed
# in). Set SKIP_TEAMS_INSTALL=1 to build the package only and skip the install.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]:-$0}")" && pwd)"

# ---- Ids baked in by azd deploy (do not edit) -------------------------------
AGENT_NAME="{{.AgentName}}"
BOT_ID="{{.MsaAppID}}"       # Teams manifest bots[].botId = the Azure Bot msaAppId
TEAMS_APP_ID="{{.TeamsAppId}}" # stable per agent, so re-runs update the same app

# Teams manifest v1.19 caps name.short at 30 and description.short at 80 chars,
# but agent names may be longer, so bound the constrained fields.
SHORT_NAME="$(printf '%.30s' "$AGENT_NAME")"
SHORT_DESC="$(printf '%.80s' "Chat with $SHORT_NAME in Microsoft Teams.")"

# Teams only treats a re-uploaded package (same app id) as an update when the
# manifest version is higher, so we need a strictly increasing version on every
# run -- even two runs in the same second. Persist a monotonic build number next
# to this script (seeded from wall-clock seconds, then always at least
# last + 1) and encode it into two bounded components (Teams caps each at 65535):
# minor = N / 65536, patch = N % 65536. N ~ epoch keeps minor < 65535 until ~2106.
STATE_FILE="$SCRIPT_DIR/.teams-app-version"
NOW_EPOCH="$(date -u +%s)"
LAST_N=0
# Only read the counter from a plain regular file -- never follow a symlink.
if [ -f "$STATE_FILE" ] && [ ! -L "$STATE_FILE" ]; then
  LAST_N="$(tr -dc '0-9' < "$STATE_FILE" 2>/dev/null)"
  [ -z "$LAST_N" ] && LAST_N=0
fi
VER_N="$NOW_EPOCH"
if [ "$((LAST_N + 1))" -gt "$VER_N" ]; then
  VER_N="$((LAST_N + 1))"
fi
VER_MINOR="$(( VER_N / 65536 ))"
VER_PATCH="$(( VER_N % 65536 ))"
PKG_VERSION="1.${VER_MINOR}.${VER_PATCH}"
if [ "$VER_MINOR" -gt 65535 ] || [ "$VER_PATCH" -gt 65535 ]; then
  echo "Error: computed manifest version $PKG_VERSION exceeds the Teams component limit (65535)." >&2
  exit 1
fi
# Persist the build number, but never follow a pre-existing symlink -- a planted
# link could otherwise redirect this write to truncate an arbitrary user-writable
# file. Write to a temp file in the same directory and atomically move it into
# place, which replaces the link itself rather than its target.
if [ ! -L "$STATE_FILE" ] && { [ ! -e "$STATE_FILE" ] || [ -f "$STATE_FILE" ]; }; then
  STATE_TMP="$STATE_FILE.$$.tmp"
  if printf '%s' "$VER_N" > "$STATE_TMP" 2>/dev/null; then
    mv -f "$STATE_TMP" "$STATE_FILE" 2>/dev/null || rm -f "$STATE_TMP" 2>/dev/null
  fi
fi

echo "Agent:        $AGENT_NAME"
echo "Bot ID:       $BOT_ID"
echo "Teams app id: $TEAMS_APP_ID"

# ---- Build the Teams app package in a temp dir ------------------------------
# The dir is left in place so the .zip survives for a manual sideload fallback.
BUILD_DIR="$(mktemp -d)"

cat > "$BUILD_DIR/manifest.json" <<JSON
{
  "\$schema": "https://developer.microsoft.com/en-us/json-schemas/teams/v1.19/MicrosoftTeams.schema.json",
  "manifestVersion": "1.19",
  "version": "$PKG_VERSION",
  "id": "$TEAMS_APP_ID",
  "developer": {
    "name": "Microsoft Foundry",
    "websiteUrl": "https://www.example.com",
    "privacyUrl": "https://www.example.com/privacy",
    "termsOfUseUrl": "https://www.example.com/termsofuse"
  },
  "icons": { "color": "color.png", "outline": "outline.png" },
  "name": { "short": "$SHORT_NAME", "full": "$AGENT_NAME (Activity, Teams)" },
  "description": {
    "short": "$SHORT_DESC",
    "full": "A Microsoft Foundry hosted agent on the Activity protocol. Send it a message in Teams."
  },
  "accentColor": "#5B5FC7",
  "bots": [
    { "botId": "$BOT_ID", "scopes": ["personal"], "supportsFiles": false, "isNotificationOnly": false }
  ],
  "permissions": ["identity"],
  "validDomains": []
}
JSON

# ---- Write the icons (embedded PNGs -- no image tooling needed) --------------
# color.png is 192x192, outline.png is 32x32, per the Teams manifest icon rules.
# macOS ships BSD base64 (decode flag -D); GNU/Linux uses -d.
if [ "$(uname)" = "Darwin" ]; then B64_DEC="-D"; else B64_DEC="-d"; fi
base64 "$B64_DEC" > "$BUILD_DIR/color.png" <<'COLOR_B64'
{{.ColorPngB64}}
COLOR_B64
base64 "$B64_DEC" > "$BUILD_DIR/outline.png" <<'OUTLINE_B64'
{{.OutlinePngB64}}
OUTLINE_B64

# ---- Zip the package (files at the zip root, not in a subfolder) ------------
ZIP_PATH="$BUILD_DIR/$AGENT_NAME-teams-app.zip"
(
    cd "$BUILD_DIR"
    if command -v zip >/dev/null 2>&1; then
        zip -j -q "$ZIP_PATH" manifest.json color.png outline.png
    elif command -v python3 >/dev/null 2>&1; then
        python3 - "$ZIP_PATH" <<'PYZIP'
import sys, zipfile
zp = sys.argv[1]
with zipfile.ZipFile(zp, "w", zipfile.ZIP_DEFLATED) as z:
    for f in ("manifest.json", "color.png", "outline.png"):
        z.write(f, f)
PYZIP
    else
        echo "Need 'zip' or 'python3' to build the app package." >&2
        exit 1
    fi
)
echo "Teams app package: $ZIP_PATH"

# Build-only mode: the package (with icons) is ready; skip the atk install.
if [ "${SKIP_TEAMS_INSTALL:-}" = "1" ]; then
    echo "SKIP_TEAMS_INSTALL=1 - package built; skipping the per-user Teams install."
    echo "Sideload it manually (requires custom app upload to be enabled for your tenant):"
    echo "    $ZIP_PATH"
    echo "    Teams -> Apps -> Manage your apps -> Upload an app -> Upload a custom app"
    exit 0
fi

# ---- Ensure the atk CLI is available ----------------------------------------
if ! command -v atk >/dev/null 2>&1; then
    if ! command -v npm >/dev/null 2>&1; then
        echo "Node.js/npm is required for the atk CLI (per-user Teams install). Install Node.js, then re-run this script." >&2
        exit 1
    fi
    echo "Installing the Microsoft 365 Agents Toolkit CLI (atk)..."
    npm install -g @microsoft/m365agentstoolkit-cli >/dev/null
    if ! command -v atk >/dev/null 2>&1; then
        echo "Failed to install atk. Install it manually: npm i -g @microsoft/m365agentstoolkit-cli" >&2
        exit 1
    fi
fi

# ---- Install the app for the current user (Personal scope) ------------------
echo ""
echo "Installing the Teams app for the current user (atk, scope Personal)..."
set +e
INSTALL_OUT="$(atk install --file-path "$ZIP_PATH" --scope Personal --interactive false 2>&1)"
echo "$INSTALL_OUT"
# If atk reports the user is not signed in, launch an interactive login and retry.
if echo "$INSTALL_OUT" | grep -qiE 'not (logged|signed) in|auth.*required|please login|login first|no account'; then
    echo "Not signed in - launching 'atk auth login m365' (complete the sign-in prompt)..."
    atk auth login m365
    INSTALL_OUT="$(atk install --file-path "$ZIP_PATH" --scope Personal --interactive false 2>&1)"
    echo "$INSTALL_OUT"
fi
set -e

# set -e is active again, so tolerate no TitleId match (grep exits 1) and fall
# through to the manual-sideload guidance below instead of aborting the script.
TITLE_ID="$(printf '%s' "$INSTALL_OUT" | grep -oiE 'TitleId:[[:space:]]*[^[:space:]]+' | head -n1 | sed -E 's/.*TitleId:[[:space:]]*//I' || true)"

# Teams addresses a bot 1:1 as "28:<botId>". Once the app is installed for the
# user, this opens the conversation with the agent directly.
CHAT_LINK="https://teams.microsoft.com/l/chat/0/0?users=28:$BOT_ID"

if [ -z "$TITLE_ID" ]; then
    echo ""
    echo "Could not confirm the per-user install."
    echo "If you were prompted to sign in, run 'atk auth login m365' then re-run this script."
    echo "Or sideload the package manually (requires custom app upload to be enabled for your tenant):"
    echo "    $ZIP_PATH"
    echo "    Teams -> Apps -> Manage your apps -> Upload an app -> Upload a custom app"
    # The install did not complete, so report failure (build-only mode already
    # exited 0 earlier). The package + manual steps above remain available.
    exit 1
fi

echo ""
echo "Installed for the current user (titleId: $TITLE_ID)."
echo "Chat with the agent in Teams:"
echo "    $CHAT_LINK"
